/**
 * OntoBricks - Mapping Core Module
 * Shared state and utilities for mapping management
 */

// =====================================================
// SHARED STATE
// =====================================================

// Mapping state - THE central state object
const MappingState = {
    config: {
        ontology_id: null,
        entities: [],
        relationships: []
    },
    
    // Loaded ontology
    loadedOntology: null,
    
    // Available catalogs
    availableCatalogs: [],
    
    // Track if R2RML was already auto-generated this session
    r2rmlAutoGenerated: false,
    
    // Store the generated R2RML content
    r2rmlContent: '',
    
    // Track if mapping has been validated
    mappingValidated: false,
    
    // Track initialization
    initialized: false
};

// =====================================================
// CORE UTILITY FUNCTIONS
// =====================================================

/**
 * Load existing mappings from session
 */
async function loadExistingMappings() {
    try {
        const response = await fetch('/mapping/load', { credentials: 'same-origin' });
        const result = await response.json();
        
        console.log('Mapping Core: Loaded result from session:', result);
        
        // API returns { success: true, config: { entities: [...], ... } }
        const savedConfig = result.config || result;
        
        if (savedConfig && Object.keys(savedConfig).length > 0) {
            if (savedConfig.entities && savedConfig.entities.length > 0) {
                MappingState.config.entities = savedConfig.entities;
                console.log('Mapping Core: Loaded', savedConfig.entities.length, 'entity mappings');
            }
            if (savedConfig.relationships && savedConfig.relationships.length > 0) {
                MappingState.config.relationships = savedConfig.relationships;
                console.log('Mapping Core: Loaded', savedConfig.relationships.length, 'relationship mappings');
            }
            if (savedConfig.ontology_id) {
                MappingState.config.ontology_id = savedConfig.ontology_id;
            }
        }
    } catch (error) {
        console.error('Mapping Core: Error loading existing mappings:', error);
    }
}

/**
 * Auto-save mappings to session and regenerate R2RML
 */
async function autoSaveMappings() {
    try {
        const response = await fetch('/mapping/save', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify(MappingState.config),
            credentials: 'same-origin'
        });
        
        const result = await response.json();
        if (result.success) {
            console.log('Mapping Core: Mappings auto-saved to session');
            
            // Auto-validate after each change
            await autoValidateMappings();
            
            // Auto-generate R2RML after each change
            await autoGenerateR2RML();
        } else {
            console.error('Mapping Core: Auto-save failed:', result.message);
        }
    } catch (error) {
        console.error('Mapping Core: Error auto-saving mappings:', error);
    }
}

/**
 * Auto-generate R2RML after mapping changes
 */
async function autoGenerateR2RML() {
    // Only generate if we have at least one entity mapping
    if (MappingState.config.entities.length === 0) {
        console.log('Mapping Core: Skipping R2RML generation - no entity mappings');
        // Clear the preview if it exists
        const r2rmlPreview = document.getElementById('r2rmlPreview');
        if (r2rmlPreview) {
            r2rmlPreview.value = '';
        }
        return;
    }
    
    try {
        console.log('Mapping Core: Auto-generating R2RML...');
        
        const response = await fetch('/mapping/generate', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            credentials: 'same-origin'
        });
        
        const result = await response.json();
        
        if (result.success && result.r2rml) {
            // Always update the R2RML preview textarea if it exists in the DOM
            const r2rmlPreview = document.getElementById('r2rmlPreview');
            if (r2rmlPreview) {
                r2rmlPreview.value = result.r2rml;
                console.log('Mapping Core: Updated R2RML preview textarea');
            }
            
            // Store in MappingState for reference
            MappingState.r2rmlContent = result.r2rml;
            MappingState.r2rmlAutoGenerated = true;
            
            console.log('Mapping Core: R2RML auto-generated successfully');
            console.log(`Mapping Core: R2RML stats - ${result.stats?.entities || 0} entities, ${result.stats?.relationships || 0} relationships`);
            
            // Update the navbar status indicator (green checkmark)
            if (typeof window.refreshOntologyStatus === 'function') {
                window.refreshOntologyStatus();
            }
        } else {
            console.warn('Mapping Core: R2RML generation returned no content');
        }
    } catch (error) {
        console.error('Mapping Core: Error auto-generating R2RML:', error);
    }
}

// Make autoGenerateR2RML globally available
window.autoGenerateR2RML = autoGenerateR2RML;

/**
 * Auto-validate mappings after each change
 * This runs validation silently and updates the UI status
 * Uses the same logic as the Validate button
 */
async function autoValidateMappings() {
    if (!MappingState.loadedOntology) {
        console.log('Mapping Core: Skipping auto-validation - no ontology loaded');
        MappingState.mappingValidated = false;
        return;
    }
    
    console.log('Mapping Core: Running auto-validation...');
    
    const issues = [];
    
    // Get counts - same logic as validateMapping()
    const totalClasses = MappingState.loadedOntology.classes?.length || 0;
    const totalProperties = MappingState.loadedOntology.properties?.length || 0;
    const mappedClasses = MappingState.config.entities?.length || 0;
    const mappedProperties = MappingState.config.relationships?.length || 0;
    
    // Check entity mappings - same as validateMapping()
    if (mappedClasses === 0) {
        issues.push('No entity mappings defined.');
    } else if (mappedClasses < totalClasses) {
        issues.push(`${totalClasses - mappedClasses} class(es) not mapped.`);
    }
    
    // Check relationship mappings - same as validateMapping()
    if (mappedProperties === 0 && totalProperties > 0) {
        issues.push('No relationship mappings defined.');
    } else if (mappedProperties < totalProperties) {
        issues.push(`${totalProperties - mappedProperties} property(ies) not mapped.`);
    }
    
    // Update validation state
    const isComplete = issues.length === 0;
    MappingState.mappingValidated = isComplete;
    
    // Store validation results for UI display
    MappingState.validationIssues = issues;
    
    console.log('Mapping Core: Auto-validation complete -', 
        issues.length, 'issues,', 
        'validated:', MappingState.mappingValidated);
    
    // Update UI status
    if (typeof updateMappingCompletionStatus === 'function') {
        updateMappingCompletionStatus();
    }
    
    // Update navbar indicators
    if (typeof window.refreshOntologyStatus === 'function') {
        window.refreshOntologyStatus();
    }
}

/**
 * Stamp `excluded` boolean onto each ontology class/property based on
 * the per-entry excluded flag in entities / relationships.
 */
function _stampExcludedFlags() {
    const ont = MappingState.loadedOntology;
    if (!ont) return;
    const cfg = MappingState.config;
    const exEntities = new Set(
        (cfg.entities || []).filter(m => m.excluded).map(m => m.ontology_class)
    );
    const exRels = new Set(
        (cfg.relationships || []).filter(m => m.excluded).map(m => m.property)
    );
    (ont.classes || []).forEach(c => { c.excluded = exEntities.has(c.uri); });
    (ont.properties || []).forEach(p => { p.excluded = exRels.has(p.uri); });
}

/**
 * Check loaded ontology status
 */
async function checkLoadedOntology() {
    try {
        const response = await fetch('/ontology/get-loaded-ontology', { credentials: 'same-origin' });
        const result = await response.json();
        
        console.log('Mapping Core: Ontology check result:', result.success, result.ontology ? 'has ontology' : 'no ontology');
        
        if (result.success && result.ontology) {
            MappingState.loadedOntology = result.ontology;
            MappingState.config.ontology_id = result.ontology.info.uri || null;
            
            _stampExcludedFlags();
            
            console.log('Mapping Core: Ontology loaded with', 
                result.ontology.classes?.length || 0, 'classes and',
                result.ontology.properties?.length || 0, 'properties');
            
            return true;
        } else {
            MappingState.loadedOntology = null;
            console.log('Mapping Core: No ontology loaded');
            return false;
        }
    } catch (error) {
        console.error('Mapping Core: Error checking loaded ontology:', error);
        return false;
    }
}

/**
 * Refresh all UI components after data is loaded
 */
async function refreshMappingUI() {
    console.log('Mapping Core: Refreshing UI...');
    console.log('Mapping Core: State - loadedOntology:', MappingState.loadedOntology ? 'present' : 'null');
    console.log('Mapping Core: State - entity mappings:', MappingState.config.entities.length);
    console.log('Mapping Core: State - relationship mappings:', MappingState.config.relationships.length);
    
    // Log available functions for debugging
    console.log('Mapping Core: Available functions:', {
        updateTaxonomyStatus: typeof window.updateTaxonomyStatus,
        updateMappingCompletionStatus: typeof window.updateMappingCompletionStatus
    });
    
    // Update UI components - use window. prefix to ensure global scope
    if (typeof window.updateTaxonomyStatus === 'function') {
        console.log('Mapping Core: Calling updateTaxonomyStatus');
        window.updateTaxonomyStatus();
    } else {
        console.warn('Mapping Core: updateTaxonomyStatus not found');
    }
    
    if (typeof window.updateMappingCompletionStatus === 'function') {
        console.log('Mapping Core: Calling updateMappingCompletionStatus');
        window.updateMappingCompletionStatus();
    } else {
        console.warn('Mapping Core: updateMappingCompletionStatus not found');
    }
    
    // Run auto-validation on initial load
    await autoValidateMappings();
    
    console.log('Mapping Core: UI refresh complete');
}

/**
 * Initialize the mapping module
 */
async function initMappingModule() {
    if (MappingState.initialized) {
        console.log('Mapping Core: Already initialized');
        return;
    }
    
    console.log('Mapping Core: Starting initialization...');
    
    // Load existing mappings first
    await loadExistingMappings();
    
    // Then check loaded ontology
    await checkLoadedOntology();
    
    // Mark as initialized
    MappingState.initialized = true;
    
    // Wait a short moment for DOM and all scripts to be fully ready
    setTimeout(() => {
        refreshMappingUI();
    }, 100);
    
    console.log('Mapping Core: Initialization complete');
}

// =====================================================
// INITIALIZATION
// =====================================================

// Note: Main initialization is done in mapping.html after all partials are loaded
// This file only defines the shared state and utility functions

console.log('Mapping Core: Module loaded, MappingState defined');

